toolArgs.file_text:
.step-indicator {
    background: var(--bs-light, #f8f9fa);
    border-radius: 0.5rem;
    padding: 1rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    align-items: flex-start;
    gap: 0.25rem;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    text-align: center;
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    right: 50%;
    height: 2px;
    background: var(--bs-border-color, #dee2e6);
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.active + .step-item::before {
    background: var(--bs-primary, #0d6efd);
}

/* keep connectors for completed-to-completed */
.step-item.completed + .step-item.completed::before {
    background: var(--bs-success, #198754);
}

.step-circle {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    position: relative;
    z-index: 1;
    border: 2px solid var(--bs-border-color, #dee2e6);
    background: #fff;
    color: var(--bs-secondary, #6c757d);
}

.step-item.active .step-circle {
    background: var(--bs-primary, #0d6efd);
    border-color: var(--bs-primary, #0d6efd);
    color: #fff;
}

.step-item.completed .step-circle {
    background: var(--bs-success, #198754);
    border-color: var(--bs-success, #198754);
    color: #fff;
}

.step-item.future .step-circle {
    opacity: 0.5;
}

.step-label {
    margin-top: 0.4rem;
    font-size: 0.78rem;
    line-height: 1.2;
    color: var(--bs-secondary, #6c757d);
}

.step-item.active .step-label {
    color: var(--bs-primary, #0d6efd);
    font-weight: 600;
}

.step-item.completed .step-label {
    color: var(--bs-success, #198754);
}

.step-item.future .step-label {
    opacity: 0.5;
}

.step-button {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
}

.step-button:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

.step-button:hover .step-label {
    text-decoration: underline;
}

