{"file_text": "<h4 class="mb-3">Personal Information</h4>

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger mt-3 mb-0">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public IApplicationService AppService { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private List<string> Errors { get; set; } = [];
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors = Model.Validate();
        if (Errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var emailValid = await AppService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                Errors.Add("Please enter a valid email address.");
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}
