{"file_text": "<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12"
              @bind="CoverLetter" @bind:event="oninput"
              maxlength="@MaxLength"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger mb-0">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter]
    public string CoverLetter { get; set; } = "";

    [Parameter]
    public EventCallback<string> CoverLetterChanged { get; set; }

    [Parameter]
    public EventCallback OnNext { get; set; }

    [Parameter]
    public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = [];

    private async Task HandleNext()
    {
        Errors = [];
        if (string.IsNullOrWhiteSpace(CoverLetter))
            Errors.Add("Cover letter is required.");
        else if (CoverLetter.Length > MaxLength)
            Errors.Add($"Cover letter must be {MaxLength} characters or fewer.");

        if (Errors.Count == 0)
            await OnNext.InvokeAsync();
    }

    protected override async Task OnParametersSetAsync()
    {
        // Keep parent in sync when user types
    }

    private new async Task InvokeAsync(Action action)
    {
        action();
        await Task.CompletedTask;
    }
}
