@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedUpTo="_completedUpTo"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personalInfo"
                                  AppService="AppService"
                                  OnNext="NextStep" />
                break;

            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;

            case 2:
                <ReferencesStep References="_references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;

            case 3:
                <CoverLetterStep CoverLetter="@_coverLetter"
                                 CoverLetterChanged="HandleCoverLetterChanged"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;

            case 4:
                <ReviewStep Personal="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="@_coverLetter"
                            AppService="AppService"
                            OnBack="PreviousStep"
                            OnEditStep="GoToStep"
                            OnSubmitted="HandleSubmitted" />
                break;
        }
    </div>
</div>

@code {
    private const int TotalSteps = 5;

    private int _currentStep;
    private int _completedUpTo;

    // Form state
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep()
    {
        if (_currentStep < TotalSteps - 1)
        {
            _currentStep++;
            if (_completedUpTo < _currentStep)
                _completedUpTo = _currentStep;
        }
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step < _completedUpTo)
            _currentStep = step;
    }

    private void HandleCoverLetterChanged(string value)
    {
        _coverLetter = value;
    }

    private void HandleSubmitted(int applicationId)
    {
        // The ReviewStep handles the confirmation display internally
    }
}

